  "code": "def minPath(grid, k):
    n = len(grid)
    min_val = float('inf')
    start_i, start_j = -1, -1
    for i in range(n):
        for j in range(n):
            if grid[i][j] < min_val:
                min_val = grid[i][j]
                start_i, start_j = i, j
    seq = [min_val]
    i, j = start_i, start_j
    dirs = [(-1,0), (1,0), (0,-1), (0,1)]
    for _ in range(1, k):
        best_val = float('inf')
        best_i, best_j = -1, -1
        for di, dj in dirs:
            ni, nj = i+di, j+dj
            if 0 <= ni < n and 0 <= nj < n:
                val = grid[ni][nj]
                if val < best_val:
                    best_val = val
                    best_i, best_j = ni, nj
        seq.append(best_val)
        i, j = best_i, best_j
    return seq",
